import {
  EVENTS,
  FORM_ERROR_MESSAGE_CLASS,
  INPUT_FIELDS,
  MODAL_OPTIONS,
} from '../constants'

import { parseJSON } from '../helpers'

class Form {
  currentAction = 0
  submitActions = []

  /**
   * Binds some simple logic to the form.
   *
   * @param {Element} form The form element
   */
  constructor(form) {
    this.form   = form
    this.fields = [ ...this.form.querySelectorAll(INPUT_FIELDS) ]

    // Parse the `data-submit-action` attribute if it exists
    const submitActions = form.getAttribute('data-submit-actions')

    if (submitActions) {
      this.submitActions = parseJSON(submitActions)
    }

    // Create a new error container for the form
    this.createErrorContainer()

    // Bind the event listeners
    this.bindFormEventListeners()

    // Bind specific listeners to form fields that require one or more
    this.bindFormFieldEventListeners()
  }

  set errorMessage(message) {
    this.errorContainer.innerHTML = message
  }

  createErrorContainer() {
    const errorContainer = this.errorContainer = document.createElement('div')
    const errorInside    = this.form.getAttribute('data-error-inside') === 'true'

    errorContainer.classList.add(FORM_ERROR_MESSAGE_CLASS)
    errorContainer.style.maxWidth = window.getComputedStyle(this.form).width

    if (errorInside) {
      this.form.insertBefore(errorContainer, this.form.firstChild)
    } else {
      this.form.parentNode.insertBefore(errorContainer, this.form)
    }
  }

  bindFormEventListeners() {
    this.form.addEventListener(EVENTS.FORM_SUBMIT.type, e => {
      this.runSubmitActions()
    })

    this.form.addEventListener('form.error', e => {
      this.errorMessage = 'Please complete all required fields'
    })
  }

  bindFormFieldEventListeners() {
    this.fields.forEach(field => {
      if (field.type === 'file') {
        this.bindFileUploadEventListener(field)
      }
    })
  }

  /**
   * Binds a change event to the file input field.
   *
   * @param {Element} field The form field
   */
  bindFileUploadEventListener(field) {
    const listClass = `${field.parentNode.className}-list`

    // Create a list container to store the selected files in
    const fileList = document.createElement('div')
    fileList.classList.add(listClass)

    field.insertAdjacentElement('afterend', fileList)

    // Bind the change event
    field.addEventListener('change', e => {
      fileList.innerHTML = '';

      // Create the list
      const files = e.target.files

      for (let file in files) {
        if (files.hasOwnProperty(file)) {
          file = files[file]

          // Create a new element for the file
          const listItem = document.createElement('div')
          listItem.classList.add(`${listClass}-item`)
          listItem.innerHTML = escape(file.name)

          // Append the list item
          fileList.appendChild(listItem)
        }
      }
    })
  }

  runSubmitActions() {
    const submitActions = this.submitActions

    const promise = new Promise((resolve, reject) => {
      // Construct a promise chain that acts similarly to `Promise.all` but in a synchronous
      // way that ensures they all run in order.
      if (submitActions.length > 1) {
        this.setupNextAction(resolve, reject)

      // Run the only defined action then resolve the promise
      } else if (submitActions.length === 1) {
        this.runSubmitAction(submitActions[0]).then(resolve)

      // Resolve the promise straight away as we have no actions
      } else {
        resolve()
      }
    })

    // Reset the form
    promise
      .then(() => this.resetForm())
      .catch(err => {
        console.error('Form.runSubmitActions:', err)

        this.currentAction = 0
        this.errorMessage  = err
      })
  }

  setupNextAction(resolve, reject) {
    const actions    = this.submitActions
    const nextAction = this.runSubmitAction(actions[this.currentAction])

    nextAction
      .then(() => {
        if (this.currentAction === actions.length - 1) {
          resolve()
        } else {
          ++this.currentAction
          this.setupNextAction(resolve, reject)
        }
      })
      .catch(reject)
  }

  runSubmitAction(action) {
    let form = this.form
    return new Promise((resolve, reject) => {
      switch (action.type) {
        case 'submit':
          form.submit()
          break

        case 'xhr':
          console.log(this.getFieldValues())
          // reject('XHR not yet implemented!')
          break

        case 'modal':
          import(/* webpackChunkName: "micromodal" */ 'micromodal/dist/micromodal')
            .then(MicroModal => {
              const openModals = document.querySelectorAll('.modal.is-open')

              if (openModals.length) {
                MicroModal.close()
              }

              // Open the new modal
              MicroModal.show(action.id, MODAL_OPTIONS)
            })
            .catch(console.error)
          break

        default:
          // No type set therefore we don't need to do anything
      }

      resolve()
    })
  }

  /**
   * Resets the form back to its original state before any user interaction.
   */
  resetForm() {
    this.form.reset()

    // Clear any file lists
    this.fields.forEach(field => {
      if (field.type === 'file') {
        field.nextSibling.innerHTML = '';
      }
    })

    // Reset the action counter
    this.currentAction = 0

    // Clear any of the validation classes and reset the ARIA attributes
    if (this.form.validation) {
      this.form.validation.resetValidation()
    }
  }

  getFieldValues() {
    const fields = {}

    this.fields.forEach(field => {
      if (field.type === 'file') {
        const files = field.files
        fields[field.name] = []

        for (let file in files) {
          if (files.hasOwnProperty(file)) {
            fields[field.name].push(files[file])
          }
        }
      } else {
        fields[field.name] = field.value
      }
    })

    return fields
  }
}

export default Form



